const express = require('express');
const app = express();
app.use(express.json());

app.post('/rappi/webhook', async (req, res) => {
  // Responde 200 imediatamente
  res.status(200).json({ received: true });

  const { event_type, order_id } = req.body;

  // Processa de forma assíncrona
  try {
    switch (event_type) {
      case 'order_created':
        await handleNewOrder(req.body);
        break;
      case 'courier_assigned':
        await handleCourierAssigned(req.body);
        break;
      case 'order_finished':
        await handleOrderFinished(req.body);
        break;
      default:
        console.log(`Evento não tratado: ${event_type}`);
    }
  } catch (err) {
    console.error(`Erro ao processar ${order_id}:`, err);
  }
});

async function handleNewOrder(payload) {
  // 1. Verificar idempotência
  if (await db.orderExists(payload.order_id)) return;

  // 2. Salvar pedido no banco
  await db.saveOrder(payload);

  // 3. Inserir no ERP/OMS
  await erpClient.createOrder(payload);

  // 4. Notificar equipe de separação
  await notifyPickingTeam(payload.order_id);
}

